import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { useAuth } from '../hooks/useAuth';

const ROLE_OPTIONS = [
  {
    value: 'user',
    label: 'User',
    tagline: 'Discover & book workspaces',
    description: 'Search, filter, and reserve desks, meeting rooms, and offices on demand.'
  },
  {
    value: 'workspace_owner',
    label: 'Workspace Owner',
    tagline: 'Manage & monetize spaces',
    description: 'Publish listings, handle bookings, and grow your workspace business.'
  }
];

export default function Login() {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    role: ROLE_OPTIONS[0].value
  });
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [token, setToken] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsLoading(true);
    try {
      const payload = {
        email: formData.email.trim(),
        password: formData.password
      };

      if (!isAdminLogin) {
        payload.role = formData.role;
      }

      const response = await login(payload);
      setIsLoading(false);
      setSuccess('Login successful!');
      setToken(response.token);
      
      // Wait a bit for auth context to update, then redirect based on role
      setTimeout(() => {
        // Check role from login response (backend returns user with role)
        const userRole = response?.user?.role;
        
        // Redirect based on role
        if (userRole === 'admin') {
          navigate('/admin', { replace: true });
        } else if (userRole === 'workspace_owner') {
          navigate('/workspace-owner', { replace: true });
        } else {
          navigate('/dashboard', { replace: true });
        }
      }, 1200);
    } catch (err) {
      setIsLoading(false);
      setError(err.message || 'Unable to sign in. Please try again.');
    }
  };

  const handleChange = (e) => {
    if (error) {
      setError('');
    }
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleRoleSelect = (roleValue) => {
    if (error) {
      setError('');
    }
    setFormData((prev) => ({ ...prev, role: roleValue }));
  };

  const toggleAdminLogin = () => {
    setIsAdminLogin((prev) => !prev);
    if (error) {
      setError('');
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Login Section - Split Screen Design */}
        <section className="relative min-h-[calc(100vh-80px)] flex flex-col lg:flex-row bg-white overflow-hidden">
          {/* Left Side - Branded Background */}
          <div className="relative w-full lg:w-2/5 h-[40vh] lg:h-auto bg-gradient-to-br from-indigo-950 via-blue-950 to-indigo-950 order-2 lg:order-1">
            {/* Geometric Background Elements */}
            <div className="absolute inset-0 opacity-20">
              <div className="absolute top-20 right-10 w-64 h-64 bg-sky-400 rounded-full blur-3xl"></div>
              <div className="absolute bottom-32 left-10 w-48 h-48 bg-rose-400 rounded-full blur-3xl"></div>
              <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-2 border-sky-400/30 rounded-full blur-xl"></div>
            </div>
            
            {/* Gradient Overlay */}
            <div className="absolute inset-0 bg-gradient-to-r from-indigo-950/90 via-blue-950/80 to-transparent lg:bg-gradient-to-r lg:from-indigo-950/90 lg:via-blue-950/70 lg:to-transparent"></div>
            
            {/* Content */}
            <div className="relative z-10 h-full flex items-center justify-center px-6 md:px-12 lg:px-16 py-12 lg:py-20">
              <div className="max-w-md text-center lg:text-left">
                {/* Logo Badge */}
                <div className="inline-flex items-center gap-3 mb-8">
                  <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-sky-500 via-blue-500 to-indigo-600 flex items-center justify-center shadow-2xl border-2 border-sky-400/50">
                    <span className="text-white font-black text-2xl">W</span>
                    <div className="absolute -top-1 -right-1 w-5 h-5 bg-rose-400 rounded-full border-2 border-indigo-950 shadow-lg"></div>
                  </div>
                  <div>
                    <div className="text-3xl font-black text-white">WorkNest</div>
                    <div className="text-xs text-blue-200 font-bold uppercase tracking-wider">Premium Workspaces</div>
                  </div>
                </div>
                
                {/* Welcome Message */}
                <h1 className="text-4xl md:text-5xl lg:text-6xl font-black text-white mb-4 leading-tight">
                  Welcome
                  <span className="block text-sky-400">Back</span>
                </h1>
                
                <p className="text-lg text-white/90 leading-relaxed mb-8 max-w-md">
                  Sign in to access your workspace bookings, favorites, and personalized recommendations.
                </p>
                
                {/* Trust Indicators */}
                <div className="flex flex-wrap items-center justify-center lg:justify-start gap-4 pt-6 border-t border-white/20">
                  <div className="flex items-center gap-2">
                    <svg className="w-5 h-5 text-sky-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="text-white text-sm font-bold">Secure Login</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <svg className="w-5 h-5 text-rose-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    <span className="text-white text-sm font-bold">24/7 Support</span>
                  </div>
                </div>
              </div>
            </div>
            
            {/* Accent Line */}
            <div className="absolute bottom-0 left-0 w-full h-1 bg-gradient-to-r from-sky-400 via-rose-400 to-sky-400"></div>
          </div>
          
          {/* Right Side - Login Form */}
          <div className="relative w-full lg:w-3/5 min-h-[60vh] lg:min-h-full bg-gradient-to-br from-slate-50 via-white to-indigo-50/30 order-1 lg:order-2 flex items-center justify-center">
            <div className="w-full max-w-2xl px-6 md:px-12 lg:px-20 py-12 lg:py-20">
              {/* Login Card */}
              <div className="bg-white rounded-3xl p-10 md:p-12 lg:p-14 shadow-2xl border-2 border-slate-100">
                {/* Card Header */}
                <div className="mb-8 sm:mb-10">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-14 h-14 rounded-xl bg-gradient-to-br from-sky-500 to-blue-600 flex items-center justify-center shadow-lg">
                      <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                      </svg>
                    </div>
                    <div>
                      <div className="text-4xl font-black text-indigo-950">Sign In</div>
                      <p className="text-slate-600 text-base mt-1">Enter your credentials to access your account</p>
                    </div>
                  </div>
                  <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 mt-4">
                    <p className="text-sm text-slate-500 flex-1">
                      {isAdminLogin
                        ? 'Admin mode enabled. Sign in using your admin credentials.'
                        : 'Choose your role to enable role-aware security.'}
                    </p>
                    <button
                      type="button"
                      onClick={toggleAdminLogin}
                      className="text-sm font-semibold text-sky-600 hover:text-sky-700 transition"
                    >
                      {isAdminLogin ? 'Switch to Member Login' : 'Admin? Sign in here'}
                    </button>
                  </div>
                </div>
                
                {/* Login Form */}
                <form onSubmit={handleSubmit} className="space-y-6">
                  {error && (
                    <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-rose-600">
                      {error}
                    </div>
                  )}
                  {success && (
                    <div className="space-y-3 rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-emerald-600">
                      <div>{success}</div>
                      {token && (
                        <div className="rounded-lg bg-white/70 px-3 py-2 text-sm font-mono text-emerald-700 break-all">
                          Token: {token}
                        </div>
                      )}
                    </div>
                  )}
                  {/* Email Field */}
                  <div>
                    <label className="block text-base font-bold text-slate-700 mb-3">
                      Email Address
                    </label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                        <svg className="w-6 h-6 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 12a4 4 0 10-8 0 4 4 0 008 0zm0 0v1.5a2.5 2.5 0 005 0V12a9 9 0 10-9 9m4.5-1.206a8.959 8.959 0 01-4.5 1.207" />
                        </svg>
                      </div>
                      <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleChange}
                        required
                        placeholder="your.email@example.com"
                        className="w-full h-14 pl-14 pr-5 rounded-xl border-2 border-slate-200 focus:outline-none focus:border-sky-400 bg-white font-medium text-slate-900 hover:border-sky-300 transition placeholder:text-slate-400 text-base"
                      />
                    </div>
                  </div>
                  
                  {/* Password Field */}
                  <div>
                    <label className="block text-base font-bold text-slate-700 mb-3">
                      Password
                    </label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                        <svg className="w-6 h-6 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                        </svg>
                      </div>
                      <input
                        type={showPassword ? 'text' : 'password'}
                        name="password"
                        value={formData.password}
                        onChange={handleChange}
                        required
                        placeholder="Enter your password"
                        className="w-full h-14 pl-14 pr-14 rounded-xl border-2 border-slate-200 focus:outline-none focus:border-sky-400 bg-white font-medium text-slate-900 hover:border-sky-300 transition placeholder:text-slate-400 text-base"
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute inset-y-0 right-0 pr-5 flex items-center text-slate-400 hover:text-sky-600 transition"
                      >
                        {showPassword ? (
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
                          </svg>
                        ) : (
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                          </svg>
                        )}
                      </button>
                    </div>
                  </div>

                  {/* Role Selection Field */}
                  {!isAdminLogin && (
                    <div>
                      <label className="block text-base font-bold text-slate-700 mb-3">
                        Login As
                      </label>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {ROLE_OPTIONS.map((option) => {
                          const isActive = formData.role === option.value;
                          return (
                            <button
                              type="button"
                              key={option.value}
                              onClick={() => handleRoleSelect(option.value)}
                              className={`w-full text-left rounded-2xl border-2 px-5 py-4 transition focus:outline-none focus:ring-2 focus:ring-sky-300 ${
                                isActive
                                  ? 'border-sky-500 bg-sky-50 shadow-sm'
                                  : 'border-slate-200 hover:border-slate-300 bg-white'
                              }`}
                            >
                              <div className="flex items-center justify-between">
                                <div>
                                  <p className={`text-sm font-semibold ${isActive ? 'text-sky-600' : 'text-slate-500'}`}>
                                    {option.tagline}
                                  </p>
                                  <p className="text-lg font-bold text-slate-900">{option.label}</p>
                                </div>
                                <span
                                  className={`h-4 w-4 rounded-full border-2 ${
                                    isActive ? 'border-sky-500 bg-sky-500' : 'border-slate-300'
                                  }`}
                                ></span>
                              </div>
                              <p className="text-xs text-slate-500 mt-3 leading-relaxed">{option.description}</p>
                            </button>
                          );
                        })}
                      </div>
                      <p className="text-xs text-slate-500 mt-3">
                        Admin accounts are created internally and can sign in using their credentials without selecting a role.
                      </p>
                    </div>
                  )}
                  
                  {/* Remember Me & Forgot Password */}
                  <div className="flex items-center justify-between">
                    <label className="flex items-center gap-2 cursor-pointer">
                      <input
                        type="checkbox"
                        className="w-4 h-4 rounded border-slate-300 text-sky-500 focus:ring-sky-400 focus:ring-2"
                      />
                      <span className="text-sm font-medium text-slate-700">Remember me</span>
                    </label>
                    <button
                      type="button"
                      onClick={() => alert('Password reset feature coming soon! Please contact support.')}
                      className="text-sm font-bold text-sky-600 hover:text-sky-700 transition"
                    >
                      Forgot password?
                    </button>
                  </div>
                  
                  {/* Submit Button */}
                  <button
                    type="submit"
                    disabled={isLoading}
                    className="w-full h-14 px-6 rounded-xl bg-gradient-to-r from-sky-500 via-blue-500 to-indigo-600 text-white font-bold hover:from-sky-600 hover:via-blue-600 hover:to-indigo-700 transition shadow-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed mt-8 text-lg"
                  >
                    {isLoading ? (
                      <>
                        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        Signing in...
                      </>
                    ) : (
                      <>
                        Sign In
                        <svg className="w-5 h-5 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                        </svg>
                      </>
                    )}
                  </button>
                </form>
                
                {/* Divider */}
                <div className="relative my-8">
                  <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-slate-200"></div>
                  </div>
                  <div className="relative flex justify-center text-sm">
                    <span className="px-4 bg-white text-slate-500 font-medium">Or continue with</span>
                  </div>
                </div>
                
                {/* Social Login Buttons */}
                <div className="grid grid-cols-1 gap-3 mb-6">
                  <button className="flex items-center justify-center gap-3 h-14 px-4 rounded-xl border-2 border-slate-200 hover:border-sky-300 bg-white text-slate-700 font-bold hover:bg-slate-50 transition text-base">
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                      <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                      <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                      <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                      <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                    </svg>
                    Google
                  </button>
                 
                </div>
                
                {/* Sign Up Link */}
                <div className="text-center pt-6 border-t border-slate-100">
                  <p className="text-slate-600 text-sm">
                    Don't have an account?{' '}
                    <Link to="/register" className="text-sky-600 hover:text-sky-700 font-bold transition">
                      Sign up for free
                    </Link>
                  </p>
                </div>
              </div>
            </div>
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
